service: samy-backend

params:
  default:
    DATABASE_URL_PRODUCTION: ${env:DATABASE_URL_PRODUCTION, ''}
    REQRES_API_URL: ${env:REQRES_API_URL, 'https://reqres.in/api'}
    REQRES_API_KEY: 'pub_6b4f29d17e8c76826f0b866585d8bee8a2b5e8dc8a7fdd43c8bd26e66bf7f56e'
    CORS_ORIGIN: ${env:CORS_ORIGIN, '*'}
